public boolean sameEnds(int[] nums, int n)
{
    for (int i = 0; i < n; i++)
    {
        if (nums[i] != nums[nums.length - n + i])
            return false;
    }
    return true;
}

public int luckySum(int a, int b, int c)
{
    if (a == 13) // if a is equal to 13
        return 0;
    if (b == 13) // if b is equal to 13 go to the a value
        return a;
    if (c == 13) //if c is 13, only add  and b
        return (a + b);
    return (a + b + c); //if none of the others,add all the numbers
}

private boolean canBalance(int[] nums) {
    int first = 0;
    int second = 0;

    for(int i = 0; i < nums.length; i++)
        second += nums[i];

    for(int i = 0; i <= nums.length - 2; i++) {
        first += nums[i];
        second -= nums[i];

        if(first == second)
            return true;
    }

    return false;
}

